import type { PropsWithChildren } from 'react';
export const VendorModal=({title,onClose,children,wide=false}:PropsWithChildren<{title:string;onClose:()=>void;wide?:boolean}>)=><div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-950/60 p-4" role="dialog" aria-modal="true" aria-label={title} onMouseDown={e=>{if(e.currentTarget===e.target)onClose();}}><section className={`max-h-[92vh] w-full overflow-y-auto rounded-2xl border border-slate-200 bg-white shadow-2xl dark:border-slate-700 dark:bg-slate-900 ${wide?'max-w-5xl':'max-w-2xl'}`}><header className="sticky top-0 z-10 flex items-center justify-between border-b border-slate-200 bg-white px-6 py-4 dark:border-slate-700 dark:bg-slate-900"><h2 className="text-lg font-bold text-slate-900 dark:text-white">{title}</h2><button type="button" onClick={onClose} className="rounded-lg p-2 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-800" aria-label="Close">✕</button></header><div className="p-6">{children}</div></section></div>;
